17	package org.springframework.boot.context.properties;
18	
19	import org.jspecify.annotations.Nullable;
20	
21	import org.springframework.beans.BeansException;
22	import org.springframework.beans.factory.InitializingBean;
23	import org.springframework.beans.factory.config.BeanDefinition;
24	import org.springframework.beans.factory.config.BeanPostProcessor;
25	import org.springframework.beans.factory.support.BeanDefinitionBuilder;
26	import org.springframework.beans.factory.support.BeanDefinitionRegistry;
27	import org.springframework.boot.context.properties.bind.BindMethod;
28	import org.springframework.context.ApplicationContext;
29	import org.springframework.context.ApplicationContextAware;
30	import org.springframework.core.Ordered;
31	import org.springframework.core.PriorityOrdered;
32	import org.springframework.core.env.PropertySources;
33	import org.springframework.util.Assert;
34	
35	/**
36	 * {@link BeanPostProcessor} to bind {@link PropertySources} to beans annotated with
37	 * {@link ConfigurationProperties @ConfigurationProperties}.
38	 *
39	 * @author Dave Syer
40	 * @author Phillip Webb
41	 * @author Christian Dupuis
42	 * @author Stephane Nicoll
43	 * @author Madhura Bhave
44	 * @since 1.0.0
45	 */
46	public class ConfigurationPropertiesBindingPostProcessor
47			implements BeanPostProcessor, PriorityOrdered, ApplicationContextAware, InitializingBean {
48	
49		/**
50		 * The bean name that this post-processor is registered with.
51		 */
52		public static final String BEAN_NAME = ConfigurationPropertiesBindingPostProcessor.class.getName();
53	
54		@SuppressWarnings("NullAway.Init")
55		private ApplicationContext applicationContext;
56	
57		@SuppressWarnings("NullAway.Init")
58		private BeanDefinitionRegistry registry;
59	
60		@SuppressWarnings("NullAway.Init")
61		private ConfigurationPropertiesBinder binder;
62	
63		@Override
64		public void setApplicationContext(ApplicationContext applicationContext) throws BeansException {
65			this.applicationContext = applicationContext;
66		}
67	
68		@Override
69		public void afterPropertiesSet() throws Exception {
70			// We can't use constructor injection of the application context because
71			// it causes eager factory bean initialization
72			this.registry = (BeanDefinitionRegistry) this.applicationContext.getAutowireCapableBeanFactory();
73			this.binder = ConfigurationPropertiesBinder.get(this.applicationContext);
74		}
75	
76		@Override
77		public int getOrder() {
78			return Ordered.HIGHEST_PRECEDENCE + 1;
79		}
80	
81		@Override
82		public Object postProcessBeforeInitialization(Object bean, String beanName) throws BeansException {
83			if (!hasBoundValueObject(beanName)) {
84				bind(ConfigurationPropertiesBean.get(this.applicationContext, bean, beanName));
85			}
86			return bean;
87		}
88	
89		private boolean hasBoundValueObject(String beanName) {
90			return BindMethod.VALUE_OBJECT.equals(BindMethodAttribute.get(this.registry, beanName));
91		}
92	
93		private void bind(@Nullable ConfigurationPropertiesBean bean) {
94			if (bean == null) {
95				return;
96			}
97			Assert.state(bean.asBindTarget().getBindMethod() != BindMethod.VALUE_OBJECT,
98					"Cannot bind @ConfigurationProperties for bean '" + bean.getName()
99							+ "'. Ensure that @ConstructorBinding has not been applied to regular bean");
100			try {
101				this.binder.bind(bean);
102			}
103			catch (Exception ex) {
104				throw new ConfigurationPropertiesBindException(bean, ex);
105			}
106		}
107	
108		/**
109		 * Register a {@link ConfigurationPropertiesBindingPostProcessor} bean if one is not
110		 * already registered.
111		 * @param registry the bean definition registry
112		 * @since 2.2.0
113		 */
114		public static void register(BeanDefinitionRegistry registry) {
115			Assert.notNull(registry, "'registry' must not be null");
116			if (!registry.containsBeanDefinition(BEAN_NAME)) {
117				BeanDefinition definition = BeanDefinitionBuilder
118					.rootBeanDefinition(ConfigurationPropertiesBindingPostProcessor.class)
119					.getBeanDefinition();
120				definition.setRole(BeanDefinition.ROLE_INFRASTRUCTURE);
121				registry.registerBeanDefinition(BEAN_NAME, definition);
122			}
123			ConfigurationPropertiesBinder.register(registry);
124		}
125	
126	}
