338		/**
339		 * Bind the specified target {@link Bindable} using this binder's
340		 * {@link ConfigurationPropertySource property sources} or create a new instance using
341		 * the type of the {@link Bindable} if the result of the binding is {@code null}.
342		 * @param name the configuration property name to bind
343		 * @param target the target bindable
344		 * @param handler the bind handler (may be {@code null})
345		 * @param <T> the bound or created type
346		 * @return the bound or created object
347		 * @since 2.2.0
348		 */
349		@SuppressWarnings("NullAway") // https://github.com/uber/NullAway/issues/1232
350		public <T> T bindOrCreate(ConfigurationPropertyName name, Bindable<T> target, @Nullable BindHandler handler) {
351			return bind(name, target, handler, true);
352		}
353	
354		@Contract("_, _, _, true -> !null")
355		private <T> @Nullable T bind(ConfigurationPropertyName name, Bindable<T> target, @Nullable BindHandler handler,
356				boolean create) {
357			Assert.notNull(name, "'name' must not be null");
358			Assert.notNull(target, "'target' must not be null");
359			handler = (handler != null) ? handler : this.defaultBindHandler;
360			Context context = new Context();
361			return bind(name, target, handler, context, false, create);
362		}
363	
364		@Contract("_, _, _, _, _, true -> !null")
365		private <T> @Nullable T bind(ConfigurationPropertyName name, Bindable<T> target, BindHandler handler,
366				Context context, boolean allowRecursiveBinding, boolean create) {
367			try (ConfigurationPropertyCaching.CacheOverride cacheOverride = this.configurationPropertyCaching.override()) {
368				try {
369					Bindable<T> replacementTarget = handler.onStart(name, target, context);
370					if (replacementTarget == null) {
371						return handleBindResult(name, target, handler, context, null, create);
372					}
373					target = replacementTarget;
374					Object bound = bindObject(name, target, handler, context, allowRecursiveBinding);
375					return handleBindResult(name, target, handler, context, bound, create);
376				}
377				catch (Exception ex) {
378					return handleBindError(name, target, handler, context, ex);
379				}
380			}
381		}
382	
383		@Contract("_, _, _, _, _, true -> null")
384		private <T> @Nullable T handleBindResult(ConfigurationPropertyName name, Bindable<T> target, BindHandler handler,
385				Context context, @Nullable Object result, boolean create) throws Exception {
386			if (result != null) {
387				result = handler.onSuccess(name, target, context, result);
388				result = context.getConverter().convert(result, target);
389			}
390			if (result == null && create) {
391				result = fromDataObjectBinders(target.getBindMethod(),
392						(dataObjectBinder) -> dataObjectBinder.create(target, context));
393				if (result == null) {
394					IllegalStateException ex = new IllegalStateException(
395							"Unable to create instance for " + target.getType());
396					List<DataObjectBinder> dataObjectBinders = this.dataObjectBinders.get(target.getBindMethod());
397					Assert.state(dataObjectBinders != null, "'dataObjectBinders' must not be null");
398					dataObjectBinders
399						.forEach((dataObjectBinder) -> dataObjectBinder.onUnableToCreateInstance(target, context, ex));
400					throw ex;
401				}
402				result = handler.onCreate(name, target, context, result);
403				result = context.getConverter().convert(result, target);
404			}
405			handler.onFinish(name, target, context, result);
406			return context.getConverter().convert(result, target);
407		}
408	
409		private <T> @Nullable T handleBindError(ConfigurationPropertyName name, Bindable<T> target, BindHandler handler,
410				Context context, Exception error) {
411			try {
412				Object result = handler.onFailure(name, target, context, error);
413				return context.getConverter().convert(result, target);
414			}
415			catch (Exception ex) {
416				if (ex instanceof BindException bindException) {
417					throw bindException;
418				}
419				throw new BindException(name, target, context.getConfigurationProperty(), ex);
420			}
421		}
422	
423		private <T> @Nullable Object bindObject(ConfigurationPropertyName name, Bindable<T> target, BindHandler handler,
424				Context context, boolean allowRecursiveBinding) {
425			ConfigurationProperty property = findProperty(name, target, context);
426			if (property == null && context.depth != 0 && containsNoDescendantOf(context.getSources(), name)) {
427				return null;
428			}
429			AggregateBinder<?> aggregateBinder = getAggregateBinder(target, context);
430			if (aggregateBinder != null) {
431				return bindAggregate(name, target, handler, context, aggregateBinder);
432			}
433			if (property != null) {
434				try {
435					return bindProperty(target, context, property);
436				}
437				catch (ConverterNotFoundException ex) {
438					// We might still be able to bind it using the recursive binders
439					boolean fallbackToDefaultValue = ObjectUtils.isEmpty(property.getValue());
440					Object instance = bindDataObject(name, target, handler, context, allowRecursiveBinding,
441							fallbackToDefaultValue);
442					if (instance != null) {
443						return instance;
444					}
445					throw ex;
446				}
447			}
448			return bindDataObject(name, target, handler, context, allowRecursiveBinding, false);
449		}
450	
451		private @Nullable AggregateBinder<?> getAggregateBinder(Bindable<?> target, Context context) {
452			Class<?> resolvedType = target.getType().resolve(Object.class);
453			if (Map.class.isAssignableFrom(resolvedType)) {
454				return new MapBinder(context);
455			}
456			if (Collection.class.isAssignableFrom(resolvedType)) {
457				return new CollectionBinder(context);
458			}
459			if (target.getType().isArray()) {
460				return new ArrayBinder(context);
461			}
462			return null;
463		}
464	
465		private <T> @Nullable Object bindAggregate(ConfigurationPropertyName name, Bindable<T> target, BindHandler handler,
466				Context context, AggregateBinder<?> aggregateBinder) {
467			AggregateElementBinder elementBinder = (itemName, itemTarget, source) -> {
468				boolean allowRecursiveBinding = aggregateBinder.isAllowRecursiveBinding(source);
469				Supplier<?> supplier = () -> bind(itemName, itemTarget, handler, context, allowRecursiveBinding, false);
470				return context.withSource(source, supplier);
471			};
472			Supplier<@Nullable Object> supplier = () -> aggregateBinder.bind(name, target, elementBinder);
473			return context.withIncreasedDepth(supplier);
474		}
475	
476		private <T> @Nullable ConfigurationProperty findProperty(ConfigurationPropertyName name, Bindable<T> target,
477				Context context) {
478			if (name.isEmpty() || target.hasBindRestriction(BindRestriction.NO_DIRECT_PROPERTY)) {
479				return null;
480			}
481			for (ConfigurationPropertySource source : context.getSources()) {
482				ConfigurationProperty property = source.getConfigurationProperty(name);
483				if (property != null) {
484					return property;
485				}
486			}
487			return null;
488		}
489	
490		private <T> @Nullable Object bindProperty(Bindable<T> target, Context context, ConfigurationProperty property) {
491			context.setConfigurationProperty(property);
492			Object result = property.getValue();
493			result = this.placeholdersResolver.resolvePlaceholders(result);
494			result = context.getConverter().convert(result, target);
495			return result;
496		}
497	
498		private @Nullable Object bindDataObject(ConfigurationPropertyName name, Bindable<?> target, BindHandler handler,
499				Context context, boolean allowRecursiveBinding, boolean fallbackToDefaultValue) {
500			if (isUnbindableBean(name, target, context)) {
501				return null;
502			}
503			Class<?> type = target.getType().resolve(Object.class);
504			BindMethod bindMethod = target.getBindMethod();
505			if (!allowRecursiveBinding && context.isBindingDataObject(type)) {
506				return null;
507			}
508			DataObjectPropertyBinder propertyBinder = (propertyName, propertyTarget) -> bind(name.append(propertyName),
509					propertyTarget, handler, context, false, false);
510			Supplier<@Nullable Object> supplier = () -> fromDataObjectBinders(bindMethod,
511					(dataObjectBinder) -> dataObjectBinder.bind(name, target, context, propertyBinder,
512							fallbackToDefaultValue));
513			return context.withDataObject(type, supplier);
514		}
515	
516		private @Nullable Object fromDataObjectBinders(@Nullable BindMethod bindMethod,
517				Function<DataObjectBinder, @Nullable Object> operation) {
518			List<DataObjectBinder> dataObjectBinders = this.dataObjectBinders.get(bindMethod);
519			Assert.state(dataObjectBinders != null, "'dataObjectBinders' must not be null");
520			for (DataObjectBinder dataObjectBinder : dataObjectBinders) {
521				Object bound = operation.apply(dataObjectBinder);
522				if (bound != null) {
523					return bound;
524				}
525			}
526			return null;
527		}
528	
529		private boolean isUnbindableBean(ConfigurationPropertyName name, Bindable<?> target, Context context) {
530			for (ConfigurationPropertySource source : context.getSources()) {
531				if (source.containsDescendantOf(name) == ConfigurationPropertyState.PRESENT) {
532					// We know there are properties to bind so we can't bypass anything
533					return false;
534				}
535			}
536			Class<?> resolved = target.getType().resolve(Object.class);
537			if (resolved.isPrimitive() || NON_BEAN_CLASSES.contains(resolved)) {
538				return true;
539			}
540			return resolved.getName().startsWith("java.");
541		}
542	
543		private boolean containsNoDescendantOf(Iterable<ConfigurationPropertySource> sources,
544				ConfigurationPropertyName name) {
545			for (ConfigurationPropertySource source : sources) {
546				if (source.containsDescendantOf(name) != ConfigurationPropertyState.ABSENT) {
547					return false;
548				}
549			}
550			return true;
551		}
552	
553		/**
554		 * Create a new {@link Binder} instance from the specified environment.
555		 * @param environment the environment source (must have attached
556		 * {@link ConfigurationPropertySources})
557		 * @return a {@link Binder} instance
558		 */
559		public static Binder get(Environment environment) {
560			return get(environment, null);
561		}
562	
563		/**
564		 * Create a new {@link Binder} instance from the specified environment.
565		 * @param environment the environment source (must have attached
566		 * {@link ConfigurationPropertySources})
567		 * @param defaultBindHandler the default bind handler to use if none is specified when
568		 * binding
569		 * @return a {@link Binder} instance
570		 * @since 2.2.0
571		 */
572		public static Binder get(Environment environment, @Nullable BindHandler defaultBindHandler) {
573			Iterable<ConfigurationPropertySource> sources = ConfigurationPropertySources.get(environment);
574			PropertySourcesPlaceholdersResolver placeholdersResolver = new PropertySourcesPlaceholdersResolver(environment);
575			return new Binder(sources, placeholdersResolver, null, null, defaultBindHandler);
576		}
577	
578		/**
579		 * Context used when binding and the {@link BindContext} implementation.
580		 */
581		final class Context implements BindContext {
582	
583			private int depth;
584	
585			private final List<ConfigurationPropertySource> source = Arrays.asList((ConfigurationPropertySource) null);
586	
587			private int sourcePushCount;
588	
589			private final Deque<Class<?>> dataObjectBindings = new ArrayDeque<>();
590	
591			private final Deque<Class<?>> constructorBindings = new ArrayDeque<>();
592	
593			private @Nullable ConfigurationProperty configurationProperty;
594	
595			private void increaseDepth() {
596				this.depth++;
597			}
598	
599			private void decreaseDepth() {
600				this.depth--;
601			}
602	
603			private <T> T withSource(@Nullable ConfigurationPropertySource source, Supplier<T> supplier) {
604				if (source == null) {
605					return supplier.get();
606				}
607				ConfigurationPropertySource previous = this.source.get(0);
608				this.source.set(0, source);
609				this.sourcePushCount++;
610				try {
611					return supplier.get();
612				}
613				finally {
614					this.sourcePushCount--;
615					this.source.set(0, previous);
616				}
617			}
618	
619			private <T> @Nullable T withDataObject(Class<?> type, Supplier<@Nullable T> supplier) {
620				this.dataObjectBindings.push(type);
621				try {
622					return withIncreasedDepth(supplier);
623				}
624				finally {
625					this.dataObjectBindings.pop();
626				}
627			}
628	
629			private boolean isBindingDataObject(Class<?> type) {
630				return this.dataObjectBindings.contains(type);
631			}
632	
633			private <T> @Nullable T withIncreasedDepth(Supplier<@Nullable T> supplier) {
634				increaseDepth();
635				try {
636					return supplier.get();
637				}
638				finally {
639					decreaseDepth();
640				}
641			}
642	
643			void setConfigurationProperty(ConfigurationProperty configurationProperty) {
644				this.configurationProperty = configurationProperty;
645			}
646	
647			void clearConfigurationProperty() {
648				this.configurationProperty = null;
649			}
650	
651			void pushConstructorBoundTypes(Class<?> value) {
652				this.constructorBindings.push(value);
653			}
654	
655			boolean isNestedConstructorBinding() {
656				return !this.constructorBindings.isEmpty();
657			}
658	
659			void popConstructorBoundTypes() {
660				this.constructorBindings.pop();
661			}
662	
663			PlaceholdersResolver getPlaceholdersResolver() {
664				return Binder.this.placeholdersResolver;
665			}
666	
667			BindConverter getConverter() {
668				return Binder.this.bindConverter;
669			}
670	
671			Map<Object, Object> getCache() {
672				return Binder.this.cache;
673			}
674	
675			@Override
676			public Binder getBinder() {
677				return Binder.this;
678			}
679	
680			@Override
681			public int getDepth() {
682				return this.depth;
683			}
684	
685			@Override
686			public Iterable<ConfigurationPropertySource> getSources() {
687				if (this.sourcePushCount > 0) {
688					return this.source;
689				}
690				return Binder.this.sources;
691			}
692	
693			@Override
694			public @Nullable ConfigurationProperty getConfigurationProperty() {
695				return this.configurationProperty;
696			}
697	
698		}
699	
700	}
