143		/**
144		 * A {@link TypeDescriptor} backed by a {@link ResolvableType}.
145		 */
146		private static class ResolvableTypeDescriptor extends TypeDescriptor {
147	
148			ResolvableTypeDescriptor(ResolvableType resolvableType, Annotation[] annotations) {
149				super(resolvableType, null, annotations);
150			}
151	
152		}
153	
154		/**
155		 * A {@link ConversionService} implementation that delegates to a
156		 * {@link SimpleTypeConverter}. Allows {@link PropertyEditor} based conversion for
157		 * simple types, arrays and collections.
158		 */
159		private static class TypeConverterConversionService extends GenericConversionService {
160	
161			TypeConverterConversionService(@Nullable Consumer<PropertyEditorRegistry> initializer) {
162				ApplicationConversionService.addDelimitedStringConverters(this);
163				addConverter(new TypeConverterConverter(initializer));
164			}
165	
166			@Override
167			public boolean canConvert(@Nullable TypeDescriptor sourceType, TypeDescriptor targetType) {
168				// Prefer conversion service to handle things like String to char[].
169				if (isPrimitiveArray(targetType)) {
170					return false;
171				}
172				return super.canConvert(sourceType, targetType);
173			}
174	
175			private static boolean isPrimitiveArray(TypeDescriptor targetType) {
176				if (!targetType.isArray()) {
177					return false;
178				}
179				TypeDescriptor elementTypeDescriptor = targetType.getElementTypeDescriptor();
180				Assert.state(elementTypeDescriptor != null, "'elementTypeDescriptor' must not be null");
181				return elementTypeDescriptor.isPrimitive();
182			}
183	
184		}
185	
186		/**
187		 * {@link ConditionalGenericConverter} that delegates to {@link SimpleTypeConverter}.
188		 */
189		private static class TypeConverterConverter implements ConditionalGenericConverter {
190	
191			private static final Set<Class<?>> EXCLUDED_EDITORS;
192			static {
193				Set<Class<?>> excluded = new HashSet<>();
194				excluded.add(CustomNumberEditor.class);
195				excluded.add(CustomBooleanEditor.class);
196				excluded.add(FileEditor.class);
197				EXCLUDED_EDITORS = Collections.unmodifiableSet(excluded);
198			}
199	
200			private final @Nullable Consumer<PropertyEditorRegistry> initializer;
201	
202			// SimpleTypeConverter is not thread-safe to use for conversion but we can use it
203			// in a thread-safe way to check if conversion is possible.
204			private final SimpleTypeConverter matchesOnlyTypeConverter;
205	
206			TypeConverterConverter(@Nullable Consumer<PropertyEditorRegistry> initializer) {
207				this.initializer = initializer;
208				this.matchesOnlyTypeConverter = createTypeConverter();
209			}
210	
211			@Override
212			public Set<ConvertiblePair> getConvertibleTypes() {
213				return Set.of(new ConvertiblePair(String.class, Object.class),
214						new ConvertiblePair(String.class, Resource[].class),
215						new ConvertiblePair(String.class, Collection.class));
216			}
217	
218			@Override
219			public boolean matches(TypeDescriptor sourceType, TypeDescriptor targetType) {
220				Class<?> type = targetType.getType();
221				if (type == null || type == Object.class || Map.class.isAssignableFrom(type)) {
222					return false;
223				}
224				if (Collection.class.isAssignableFrom(type)) {
225					TypeDescriptor elementType = targetType.getElementTypeDescriptor();
226					if (elementType == null || (!Resource.class.isAssignableFrom(elementType.getType()))) {
227						return false;
228					}
229				}
230				PropertyEditor editor = this.matchesOnlyTypeConverter.getDefaultEditor(type);
231				if (editor == null) {
232					editor = this.matchesOnlyTypeConverter.findCustomEditor(type, null);
233				}
234				if (editor == null && String.class != type) {
235					editor = BeanUtils.findEditorByConvention(type);
236				}
237				return (editor != null && !EXCLUDED_EDITORS.contains(editor.getClass()));
238			}
239	
240			@Override
241			public @Nullable Object convert(@Nullable Object source, TypeDescriptor sourceType, TypeDescriptor targetType) {
242				return createTypeConverter().convertIfNecessary(source, targetType.getType(), targetType);
243			}
244	
245			private SimpleTypeConverter createTypeConverter() {
246				SimpleTypeConverter typeConverter = new SimpleTypeConverter();
247				if (this.initializer != null) {
248					this.initializer.accept(typeConverter);
249				}
250				return typeConverter;
251			}
252	
253		}
