49			// Use a local copy in case another thread changes things
50			LastMapping<ConfigurationPropertyName, List<String>> last = this.lastMappedConfigurationPropertyName;
51			if (last != null && last.isFrom(configurationPropertyName)) {
52				return last.getMapping();
53			}
54			String convertedName = configurationPropertyName.toString();
55			List<String> mapping = Collections.singletonList(convertedName);
56			this.lastMappedConfigurationPropertyName = new LastMapping<>(configurationPropertyName, mapping);
57			return mapping;
