73			try {
74				ConfigurationPropertyName convertedName = ConfigurationPropertyName.adapt(propertySourceName, '.');
75				if (!convertedName.isEmpty()) {
76					return convertedName;
77				}
78			}
79			catch (Exception ex) {
80				// Ignore
81			}
82			return ConfigurationPropertyName.EMPTY;
83		}
