93				this.mapping = mapping;
94			}
95	
96			boolean isFrom(T from) {
97				return ObjectUtils.nullSafeEquals(from, this.from);
98			}
99	
100			M getMapping() {
101				return this.mapping;
102			}
103	
104		}
