17	package org.springframework.boot.context.properties.source;
18	
19	import java.util.Arrays;
20	import java.util.Collections;
21	import java.util.ConcurrentModificationException;
22	import java.util.HashMap;
23	import java.util.HashSet;
24	import java.util.Iterator;
25	import java.util.LinkedHashMap;
26	import java.util.Map;
27	import java.util.NoSuchElementException;
28	import java.util.Objects;
29	import java.util.Set;
30	import java.util.function.BiPredicate;
31	import java.util.stream.Stream;
32	
33	import org.jspecify.annotations.Nullable;
34	
35	import org.springframework.boot.env.PropertySourceInfo;
36	import org.springframework.boot.origin.Origin;
37	import org.springframework.boot.origin.PropertySourceOrigin;
38	import org.springframework.core.env.EnumerablePropertySource;
39	import org.springframework.core.env.MapPropertySource;
40	import org.springframework.core.env.PropertySource;
41	import org.springframework.core.env.StandardEnvironment;
42	import org.springframework.core.env.SystemEnvironmentPropertySource;
43	import org.springframework.util.Assert;
44	import org.springframework.util.ConcurrentReferenceHashMap;
45	
46	/**
47	 * {@link ConfigurationPropertySource} backed by an {@link EnumerablePropertySource}.
48	 * Extends {@link SpringConfigurationPropertySource} with full "relaxed" mapping support.
49	 * In order to use this adapter the underlying {@link PropertySource} must be fully
50	 * enumerable. A security restricted {@link SystemEnvironmentPropertySource} cannot be
51	 * adapted.
52	 *
53	 * @author Phillip Webb
54	 * @author Madhura Bhave
55	 * @see PropertyMapper
56	 */
57	class SpringIterableConfigurationPropertySource extends SpringConfigurationPropertySource
58			implements IterableConfigurationPropertySource, CachingConfigurationPropertySource {
59	
60		private final BiPredicate<ConfigurationPropertyName, ConfigurationPropertyName> ancestorOfCheck;
61	
62		private final SoftReferenceConfigurationPropertyCache<Cache> cache;
63	
64		private volatile @Nullable ConfigurationPropertyName @Nullable [] configurationPropertyNames;
65	
66		private final @Nullable Map<ConfigurationPropertyName, ConfigurationPropertyState> containsDescendantOfCache;
67	
68		SpringIterableConfigurationPropertySource(EnumerablePropertySource<?> propertySource,
69				boolean systemEnvironmentSource, PropertyMapper... mappers) {
70			super(propertySource, systemEnvironmentSource, mappers);
71			assertEnumerablePropertySource();
72			boolean immutable = isImmutablePropertySource();
73			this.ancestorOfCheck = getAncestorOfCheck(mappers);
74			this.cache = new SoftReferenceConfigurationPropertyCache<>(immutable);
75			this.containsDescendantOfCache = (!systemEnvironmentSource) ? null : new ConcurrentReferenceHashMap<>();
76		}
77	
78		private BiPredicate<ConfigurationPropertyName, ConfigurationPropertyName> getAncestorOfCheck(
79				PropertyMapper[] mappers) {
80			BiPredicate<ConfigurationPropertyName, ConfigurationPropertyName> ancestorOfCheck = mappers[0]
81				.getAncestorOfCheck();
82			for (int i = 1; i < mappers.length; i++) {
83				ancestorOfCheck = ancestorOfCheck.or(mappers[i].getAncestorOfCheck());
84			}
85			return ancestorOfCheck;
86		}
87	
88		private void assertEnumerablePropertySource() {
89			if (getPropertySource() instanceof MapPropertySource mapSource) {
90				try {
91					mapSource.getSource().size();
92				}
93				catch (UnsupportedOperationException ex) {
94					throw new IllegalArgumentException("PropertySource must be fully enumerable");
95				}
96			}
97		}
98	
99		@Override
100		public ConfigurationPropertyCaching getCaching() {
101			return this.cache;
102		}
103	
104		@Override
105		public @Nullable ConfigurationProperty getConfigurationProperty(@Nullable ConfigurationPropertyName name) {
106			if (name == null) {
107				return null;
108			}
109			ConfigurationProperty configurationProperty = super.getConfigurationProperty(name);
110			if (configurationProperty != null) {
111				return configurationProperty;
112			}
113			for (String candidate : getCache().getMapped(name)) {
114				Object value = getPropertySourceProperty(candidate);
115				if (value != null) {
116					Origin origin = PropertySourceOrigin.get(getPropertySource(), candidate);
117					return ConfigurationProperty.of(this, name, value, origin);
118				}
119			}
120			return null;
121		}
122	
123		@Override
124		protected @Nullable Object getSystemEnvironmentProperty(Map<String, Object> systemEnvironment, String name) {
125			return getCache().getSystemEnvironmentProperty(name);
126		}
127	
128		@Override
129		public Stream<ConfigurationPropertyName> stream() {
130			@Nullable ConfigurationPropertyName[] names = getConfigurationPropertyNames();
131			return Arrays.stream(names).filter(Objects::nonNull);
132		}
133	
134		@Override
135		public Iterator<ConfigurationPropertyName> iterator() {
136			return new ConfigurationPropertyNamesIterator(getConfigurationPropertyNames());
137		}
138	
139		@Override
140		public ConfigurationPropertyState containsDescendantOf(ConfigurationPropertyName name) {
141			ConfigurationPropertyState result = super.containsDescendantOf(name);
142			if (result != ConfigurationPropertyState.UNKNOWN) {
143				return result;
144			}
145			if (this.ancestorOfCheck == PropertyMapper.DEFAULT_ANCESTOR_OF_CHECK) {
146				Set<ConfigurationPropertyName> descendants = getCache().getDescendants();
147				if (descendants != null) {
148					if (name.isEmpty() && !descendants.isEmpty()) {
149						return ConfigurationPropertyState.PRESENT;
150					}
151					return !descendants.contains(name) ? ConfigurationPropertyState.ABSENT
152							: ConfigurationPropertyState.PRESENT;
153				}
154			}
155			result = (this.containsDescendantOfCache != null) ? this.containsDescendantOfCache.get(name) : null;
156			if (result == null) {
157				result = (!ancestorOfCheck(name)) ? ConfigurationPropertyState.ABSENT : ConfigurationPropertyState.PRESENT;
158				if (this.containsDescendantOfCache != null) {
159					this.containsDescendantOfCache.put(name, result);
160				}
161			}
162			return result;
163		}
164	
165		private boolean ancestorOfCheck(ConfigurationPropertyName name) {
166			@Nullable ConfigurationPropertyName[] candidates = getConfigurationPropertyNames();
167			for (ConfigurationPropertyName candidate : candidates) {
168				if (candidate != null && this.ancestorOfCheck.test(name, candidate)) {
169					return true;
170				}
171			}
172			return false;
173		}
174	
175		@Nullable ConfigurationPropertyName[] getConfigurationPropertyNames() {
176			if (!isImmutablePropertySource()) {
177				return getCache().getConfigurationPropertyNames(getPropertySource().getPropertyNames());
178			}
179			@Nullable ConfigurationPropertyName[] configurationPropertyNames = this.configurationPropertyNames;
180			if (configurationPropertyNames == null) {
181				configurationPropertyNames = getCache()
182					.getConfigurationPropertyNames(getPropertySource().getPropertyNames());
183				this.configurationPropertyNames = configurationPropertyNames;
184			}
185			return configurationPropertyNames;
186		}
187	
188		private Cache getCache() {
189			return this.cache.get(this::createCache, this::updateCache);
190		}
191	
192		private Cache createCache() {
193			boolean immutable = isImmutablePropertySource();
194			boolean captureDescendants = this.ancestorOfCheck == PropertyMapper.DEFAULT_ANCESTOR_OF_CHECK;
195			return new Cache(getMappers(), immutable, captureDescendants, isSystemEnvironmentSource());
196		}
197	
198		private Cache updateCache(Cache cache) {
199			cache.update(getPropertySource());
200			return cache;
201		}
202	
203		boolean isImmutablePropertySource() {
204			EnumerablePropertySource<?> source = getPropertySource();
205			if (source instanceof PropertySourceInfo propertySourceInfo) {
206				return propertySourceInfo.isImmutable();
207			}
208			if (StandardEnvironment.SYSTEM_ENVIRONMENT_PROPERTY_SOURCE_NAME.equals(source.getName())) {
209				return source.getSource() == System.getenv();
210			}
211			return false;
212		}
213	
214		@Override
215		protected EnumerablePropertySource<?> getPropertySource() {
216			return (EnumerablePropertySource<?>) super.getPropertySource();
217		}
218	
219		private static class Cache {
220	
221			private static final ConfigurationPropertyName[] EMPTY_NAMES_ARRAY = {};
222	
223			private final PropertyMapper[] mappers;
224	
225			private final boolean immutable;
226	
227			private final boolean captureDescendants;
228	
229			private final boolean systemEnvironmentSource;
230	
231			private volatile @Nullable Data data;
232	
233			Cache(PropertyMapper[] mappers, boolean immutable, boolean captureDescendants,
234					boolean systemEnvironmentSource) {
235				this.mappers = mappers;
236				this.immutable = immutable;
237				this.captureDescendants = captureDescendants;
238				this.systemEnvironmentSource = systemEnvironmentSource;
239			}
240	
241			void update(EnumerablePropertySource<?> propertySource) {
242				if (this.data == null || !this.immutable) {
243					int count = 0;
244					while (true) {
245						try {
246							tryUpdate(propertySource);
247							return;
248						}
249						catch (ConcurrentModificationException ex) {
250							if (count++ > 10) {
251								throw ex;
252							}
253						}
254					}
255				}
256			}
257	
258			private void tryUpdate(EnumerablePropertySource<?> propertySource) {
259				Data data = this.data;
260				String[] lastUpdated = (data != null) ? data.lastUpdated() : null;
261				String[] propertyNames = propertySource.getPropertyNames();
262				if (lastUpdated != null && Arrays.equals(lastUpdated, propertyNames)) {
263					return;
264				}
265				int size = propertyNames.length;
266				Map<ConfigurationPropertyName, Set<String>> mappings = cloneOrCreate(
267						(data != null) ? data.mappings() : null, size);
268				Map<String, ConfigurationPropertyName> reverseMappings = cloneOrCreate(
269						(data != null) ? data.reverseMappings() : null, size);
270				Set<ConfigurationPropertyName> descendants = (!this.captureDescendants) ? null : new HashSet<>();
271				Map<String, Object> systemEnvironmentCopy = (!this.systemEnvironmentSource) ? null
272						: copySource(propertySource);
273				for (PropertyMapper propertyMapper : this.mappers) {
274					for (String propertyName : propertyNames) {
275						if (!reverseMappings.containsKey(propertyName)) {
276							ConfigurationPropertyName configurationPropertyName = propertyMapper.map(propertyName);
277							if (configurationPropertyName != null && !configurationPropertyName.isEmpty()) {
278								add(mappings, configurationPropertyName, propertyName);
279								reverseMappings.put(propertyName, configurationPropertyName);
280							}
281						}
282					}
283				}
284				for (String propertyName : propertyNames) {
285					addParents(descendants, reverseMappings.get(propertyName));
286				}
287				ConfigurationPropertyName[] configurationPropertyNames = this.immutable
288						? reverseMappings.values().toArray(new ConfigurationPropertyName[0]) : null;
289				lastUpdated = this.immutable ? null : propertyNames;
290				this.data = new Data(mappings, reverseMappings, descendants, configurationPropertyNames,
291						systemEnvironmentCopy, lastUpdated);
292			}
293	
294			@SuppressWarnings("unchecked")
295			private HashMap<String, Object> copySource(EnumerablePropertySource<?> propertySource) {
296				return new HashMap<>((Map<String, Object>) propertySource.getSource());
297			}
298	
299			private <K, V> Map<K, V> cloneOrCreate(@Nullable Map<K, V> source, int size) {
300				return (source != null) ? new LinkedHashMap<>(source) : new LinkedHashMap<>(size);
301			}
302	
303			private void addParents(@Nullable Set<ConfigurationPropertyName> descendants,
304					@Nullable ConfigurationPropertyName name) {
305				if (descendants == null || name == null || name.isEmpty()) {
306					return;
307				}
308				ConfigurationPropertyName parent = name.getParent();
309				while (!parent.isEmpty()) {
310					if (!descendants.add(parent)) {
311						return;
312					}
313					parent = parent.getParent();
314				}
315			}
316	
317			private <K, T> void add(Map<K, Set<T>> map, K key, T value) {
318				map.computeIfAbsent(key, (k) -> new HashSet<>()).add(value);
319			}
320	
321			Set<String> getMapped(ConfigurationPropertyName configurationPropertyName) {
322				Data data = this.data;
323				Assert.state(data != null, "'data' must not be null");
324				return data.mappings().getOrDefault(configurationPropertyName, Collections.emptySet());
325			}
326	
327			@Nullable ConfigurationPropertyName[] getConfigurationPropertyNames(String[] propertyNames) {
328				Data data = this.data;
329				Assert.state(data != null, "'data' must not be null");
330				@Nullable ConfigurationPropertyName[] names = data.configurationPropertyNames();
331				if (names != null) {
332					return names;
333				}
334				Map<String, ConfigurationPropertyName> reverseMappings = data.reverseMappings();
335				if (reverseMappings == null || reverseMappings.isEmpty()) {
336					return EMPTY_NAMES_ARRAY;
337				}
338				names = new ConfigurationPropertyName[propertyNames.length];
339				for (int i = 0; i < propertyNames.length; i++) {
340					names[i] = reverseMappings.get(propertyNames[i]);
341				}
342				return names;
343			}
344	
345			@Nullable Set<ConfigurationPropertyName> getDescendants() {
346				Data data = this.data;
347				Assert.state(data != null, "'data' must not be null");
348				return data.descendants();
349			}
350	
351			@Nullable Object getSystemEnvironmentProperty(String name) {
352				Data data = this.data;
353				Assert.state(data != null, "'data' must not be null");
354				Map<String, Object> systemEnvironmentCopy = data.systemEnvironmentCopy();
355				Assert.state(systemEnvironmentCopy != null, "'systemEnvironmentCopy' must not be null");
356				return systemEnvironmentCopy.get(name);
357			}
358	
359			private record Data(Map<ConfigurationPropertyName, Set<String>> mappings,
360					Map<String, ConfigurationPropertyName> reverseMappings,
361					@Nullable Set<ConfigurationPropertyName> descendants,
362					ConfigurationPropertyName @Nullable [] configurationPropertyNames,
363					@Nullable Map<String, Object> systemEnvironmentCopy, String @Nullable [] lastUpdated) {
364	
365			}
366	
367		}
368	
369		/**
370		 * ConfigurationPropertyNames iterator backed by an array.
371		 */
372		private static class ConfigurationPropertyNamesIterator implements Iterator<ConfigurationPropertyName> {
373	
374			private final @Nullable ConfigurationPropertyName[] names;
375	
376			private int index;
377	
378			ConfigurationPropertyNamesIterator(@Nullable ConfigurationPropertyName[] names) {
379				this.names = names;
380			}
381	
382			@Override
383			public boolean hasNext() {
384				skipNulls();
385				return this.index < this.names.length;
386			}
387	
388			@Override
389			public @Nullable ConfigurationPropertyName next() {
390				skipNulls();
391				if (this.index >= this.names.length) {
392					throw new NoSuchElementException();
393				}
394				return this.names[this.index++];
395			}
396	
397			private void skipNulls() {
398				while (this.index < this.names.length) {
399					if (this.names[this.index] != null) {
400						return;
401					}
402					this.index++;
403				}
404			}
405	
406		}
407	
408	}
